package com.example.client;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class ClientManager extends Thread {

    private static final String DEFAULT_MASTER_HOST = "127.0.0.1";
    private static final int DEFAULT_MASTER_PORT = 9000;

    private final RegionCache regionCache;
    private final MasterClient masterClient;
    private final RegionServerClient regionServerClient;

    /**
     * 构造函数（默认 Master 地址）
     */
    public ClientManager() {
        this(DEFAULT_MASTER_HOST, DEFAULT_MASTER_PORT);
    }

    /**
     * 构造函数（自定义 Master 地址）
     *
     * @param masterHost Master 主机名或 IP
     * @param masterPort Master 端口
     */
    public ClientManager(String masterHost, int masterPort) {
        this.regionCache = new RegionCache();
        this.masterClient = new MasterClient(masterHost, masterPort);
        this.regionServerClient = new RegionServerClient();
    }

    /**
     * 客户端线程主循环，接收用户请求并响应
     * 支持命令：
     * get <table> <rowKey>
     * exit
     */
    public void run() {
        System.out.println("Client started. Commands: get <table> <rowKey>, exit");
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        while (true) {
            System.out.print("> ");
            String line;
            try {
                line = reader.readLine();
            } catch (IOException e) {
                System.out.println("Input error: " + e.getMessage());
                break;
            }
            if (line == null) {
                break;
            }
            line = line.trim();
            if (line.isEmpty()) {
                continue;
            }
            if ("exit".equalsIgnoreCase(line) || "quit".equalsIgnoreCase(line)) {
                break;
            }
            String[] parts = line.split("\\s+");
            if (parts.length >= 3 && "get".equalsIgnoreCase(parts[0])) {
                String table = parts[1];
                String rowKey = parts[2];
                handleGet(table, rowKey);
            } else {
                System.out.println("Unknown command. Use: get <table> <rowKey>, exit");
            }
        }
        System.out.println("Client stopped.");
    }

    private void handleGet(String table, String rowKey) {
        RegionLocation location = regionCache.find(table);
        if (location == null) {
            location = locateFromMaster(table, rowKey);
            if (location == null) {
                return;
            }
            regionCache.set(table, location);
        }

        RegionReadResult result = readFromRegion(location, table, rowKey);
        if (result.getStatus() == RegionReadStatus.MOVED && result.getRedirectLocation() != null) {
            // Region 发生迁移，刷新缓存并重试一次
            regionCache.set(table, result.getRedirectLocation());
            result = readFromRegion(result.getRedirectLocation(), table, rowKey);
        }

        switch (result.getStatus()) {
            case OK:
                System.out.println("VALUE: " + result.getValue());
                break;
            case NOT_FOUND:
                System.out.println("NOT_FOUND");
                break;
            case MOVED:
                System.out.println("MOVED to " + result.getRedirectLocation());
                break;
            case ERROR:
            default:
                System.out.println("ERROR: " + result.getErrorMessage());
                break;
        }
    }

    private RegionLocation locateFromMaster(String table, String rowKey) {
        try {
            return masterClient.locateRegion(table, rowKey);
        } catch (IOException e) {
            System.out.println("Master locate failed: " + e.getMessage());
            return null;
        }
    }

    private RegionReadResult readFromRegion(RegionLocation location, String table, String rowKey) {
        try {
            return regionServerClient.read(location, table, rowKey);
        } catch (IOException e) {
            return RegionReadResult.error("Region read failed: " + e.getMessage());
        }
    }
}
